    def is_amicable(n):
        """Return True if n is amicable, False otherwise."""
        return n%1==0 and n%2==0 and n%3==0 and n%4==0

    def is_amicable_numbers(n):
        """Return True if n is amicable numbers, False otherwise."""
        return all(is_amicable(i) for i in range(1,n+1))

